import React, { useState, useEffect } from "react";
import axios from "axios";

const Bill = () => {
  const [bills, setBills] = useState([]);
  const [form, setForm] = useState({
    MaHD: "",
    PhongSo: "",
    NgayO: "",
    TongDV: "",
    TongTien: "",
    PhuongThucTT: "",
  });
  const [filter, setFilter] = useState({
    PhongSo: "",
    PhuongThucTT: "",
    NgayO: "",
  });
  const [report, setReport] = useState(null);

  const apiBase = "http://localhost:5000/api/bill";

  // Lấy tất cả hóa đơn
  const fetchAllBills = async () => {
    try {
      const res = await axios.get(`${apiBase}/allbills`);
      const sorted = res.data.sort((a, b) => Number(a.PhongSo) - Number(b.PhongSo));
      setBills(sorted);
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  // Lọc hóa đơn theo filter
  const fetchBills = async () => {
    try {
      const params = {};
      if (filter.PhongSo) params.PhongSo = filter.PhongSo;
      if (filter.PhuongThucTT) params.PhuongThucTT = filter.PhuongThucTT;
      if (filter.NgayO) params.NgayO = filter.NgayO;

      const res = await axios.get(`${apiBase}/managementbill`, { params });
      const sorted = res.data.sort((a, b) => Number(a.PhongSo) - Number(b.PhongSo));
      setBills(sorted);
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  // Tự load tất cả khi mở trang
  useEffect(() => {
    fetchAllBills();
  }, []);

  // Thêm hoặc cập nhật hóa đơn
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const exists = bills.find((b) => b.MaHD === form.MaHD);
      if (exists) {
        await axios.put(`${apiBase}/updatebill`, form);
        alert("Cập nhật hóa đơn thành công");
      } else {
        await axios.post(`${apiBase}/addbill`, form);
        alert("Thêm hóa đơn thành công");
      }
      setForm({
        MaHD: "",
        PhongSo: "",
        NgayO: "",
        TongDV: "",
        TongTien: "",
        PhuongThucTT: "",
      });
      fetchAllBills(); // Luôn load lại toàn bộ
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  // Xóa hóa đơn
  const handleDelete = async (MaHD) => {
    if (!window.confirm("Bạn có chắc muốn xóa hóa đơn này?")) return;
    try {
      await axios.delete(`${apiBase}/deletebill`, { data: { MaHD } });
      fetchAllBills(); // Luôn load lại toàn bộ
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  // Lấy báo cáo
  const fetchReport = async () => {
    try {
      const res = await axios.get(`${apiBase}/reportbill`);
      setReport(res.data);
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold mb-4">Quản lý hóa đơn</h1>

      {/* Form thêm/sửa hóa đơn */}
      <form className="mb-4 space-y-2" onSubmit={handleSubmit}>
        <input
          placeholder="Mã HD"
          value={form.MaHD}
          onChange={(e) => setForm({ ...form, MaHD: e.target.value })}
          className="border p-2 w-full"
        />
        <input
          placeholder="Phòng số"
          value={form.PhongSo}
          onChange={(e) => setForm({ ...form, PhongSo: e.target.value })}
          className="border p-2 w-full"
        />
        <input
          type="date"
          value={form.NgayO}
          onChange={(e) => setForm({ ...form, NgayO: e.target.value })}
          className="border p-2 w-full"
        />
        <input
          placeholder="Tổng DV"
          type="number"
          value={form.TongDV}
          onChange={(e) => setForm({ ...form, TongDV: e.target.value })}
          className="border p-2 w-full"
        />
        <input
          placeholder="Tổng tiền"
          type="number"
          value={form.TongTien}
          onChange={(e) => setForm({ ...form, TongTien: e.target.value })}
          className="border p-2 w-full"
        />
        <input
          placeholder="Phương thức TT"
          value={form.PhuongThucTT}
          onChange={(e) => setForm({ ...form, PhuongThucTT: e.target.value })}
          className="border p-2 w-full"
        />
        <button type="submit" className="bg-blue-500 text-white px-4 py-2 rounded">
          {bills.find((b) => b.MaHD === form.MaHD) ? "Cập nhật" : "Thêm hóa đơn"}
        </button>
      </form>

      {/* Filter danh sách */}
      <div className="mb-4 space-y-2">
        <h2 className="font-semibold">Tìm kiếm hóa đơn</h2>
        <input
          placeholder="Phòng số"
          value={filter.PhongSo}
          onChange={(e) => setFilter({ ...filter, PhongSo: e.target.value })}
          className="border p-2 w-full"
        />
        <input
          placeholder="Phương thức TT"
          value={filter.PhuongThucTT}
          onChange={(e) => setFilter({ ...filter, PhuongThucTT: e.target.value })}
          className="border p-2 w-full"
        />
        <input
          type="date"
          value={filter.NgayO}
          onChange={(e) => setFilter({ ...filter, NgayO: e.target.value })}
          className="border p-2 w-full"
        />
        <div className="flex space-x-2">
          <button
            type="button"
            onClick={fetchBills}
            className="bg-green-500 text-white px-4 py-2 rounded"
          >
            Tìm kiếm
          </button>
          <button
            type="button"
            onClick={fetchAllBills}
            className="bg-indigo-500 text-white px-4 py-2 rounded"
          >
            Xem tất cả
          </button>
        </div>
      </div>

      {/* Danh sách hóa đơn */}
      <table className="border w-full text-left mb-4">
        <thead>
          <tr className="bg-gray-200">
            <th className="border px-2 py-1">Mã HD</th>
            <th className="border px-2 py-1">Phòng số</th>
            <th className="border px-2 py-1">Ngày ở</th>
            <th className="border px-2 py-1">Tổng DV</th>
            <th className="border px-2 py-1">Tổng tiền</th>
            <th className="border px-2 py-1">Phương thức TT</th>
            <th className="border px-2 py-1">Hành động</th>
          </tr>
        </thead>
        <tbody>
          {bills.map((b) => (
            <tr key={b.MaHD}>
              <td className="border px-2 py-1">{b.MaHD}</td>
              <td className="border px-2 py-1">{b.PhongSo}</td>
              <td className="border px-2 py-1">
                <input
                  type="date"
                  value={b.NgayO ? new Date(b.NgayO).toISOString().split("T")[0] : ""}
                  readOnly
                  className="bg-transparent"
                />
              </td>
              <td className="border px-2 py-1">{b.TongDV}</td>
              <td className="border px-2 py-1">{b.TongTien}</td>
              <td className="border px-2 py-1">{b.PhuongThucTT}</td>
              <td className="border px-2 py-1">
                <button
                  onClick={() => setForm(b)}
                  className="bg-yellow-400 px-2 py-1 mr-2 rounded"
                >
                  Sửa
                </button>
                <button
                  onClick={() => handleDelete(b.MaHD)}
                  className="bg-red-500 px-2 py-1 rounded text-white"
                >
                  Xóa
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      {/* Báo cáo */}
      <div>
        <button
          onClick={fetchReport}
          className="bg-purple-500 text-white px-4 py-2 rounded mb-2"
        >
          Xem báo cáo
        </button>
        {report && (
          <pre className="bg-gray-100 p-2">{JSON.stringify(report, null, 2)}</pre>
        )}
      </div>
    </div>
  );
};

export default Bill;
